<?php if (!defined('ABSPATH')) exit; get_header(); while (have_posts()) : the_post(); $duracion = get_post_meta(get_the_ID(), '_duracion', true); $nivel = get_post_meta(get_the_ID(), '_nivel', true); $precio = get_post_meta(get_the_ID(), '_precio', true); $plazas = get_post_meta(get_the_ID(), '_plazas_disponibles', true); $fecha_inicio = get_post_meta(get_the_ID(), '_fecha_inicio', true); $profesor = get_post_meta(get_the_ID(), '_profesor', true); ?>
<div class="flavor-container py-8"><nav class="flex mb-6 text-sm"><ol class="inline-flex items-center space-x-2"><li><a href="<?php echo home_url('/'); ?>">Inicio</a></li><li><span class="mx-2">/</span></li><li><a href="<?php echo get_post_type_archive_link('curso'); ?>">Cursos</a></li><li><span class="mx-2">/</span></li><li><?php the_title(); ?></li></ol></nav><div class="grid lg:grid-cols-3 gap-8"><div class="lg:col-span-2"><article class="bg-white rounded-xl shadow-lg overflow-hidden"><?php if (has_post_thumbnail()) the_post_thumbnail('large', array('class' => 'w-full aspect-video object-cover')); ?><div class="p-8"><h1 class="text-4xl font-bold mb-6"><?php the_title(); ?></h1><?php if ($profesor) : ?><p class="text-lg text-gray-600 mb-6">Instructor: <strong><?php echo esc_html($profesor); ?></strong></p><?php endif; ?><div class="prose max-w-none mb-8"><?php the_content(); ?></div><div class="bg-gray-50 rounded-lg p-6"><h3 class="text-lg font-bold mb-4">Detalles del curso</h3><dl class="space-y-3"><?php if ($duracion) : ?><div><dt class="text-sm font-semibold text-gray-700">Duración:</dt><dd><?php echo esc_html($duracion); ?></dd></div><?php endif; ?><?php if ($nivel) : ?><div><dt class="text-sm font-semibold text-gray-700">Nivel:</dt><dd><?php echo esc_html($nivel); ?></dd></div><?php endif; ?><?php if ($fecha_inicio) : ?><div><dt class="text-sm font-semibold text-gray-700">Fecha de inicio:</dt><dd><?php echo date_i18n('d/m/Y', strtotime($fecha_inicio)); ?></dd></div><?php endif; ?><?php if ($plazas) : ?><div><dt class="text-sm font-semibold text-gray-700">Plazas disponibles:</dt><dd class="text-xl font-bold text-primary"><?php echo esc_html($plazas); ?></dd></div><?php endif; ?></dl></div></div></article></div><aside class="lg:col-span-1"><div class="bg-white rounded-xl shadow-lg p-6 sticky top-6"><h3 class="text-xl font-bold mb-4">Inscripción</h3><?php if ($precio) : ?><div class="mb-6"><p class="text-sm text-gray-600 mb-2">Precio</p><p class="text-4xl font-bold text-primary"><?php echo esc_html($precio); ?>€</p></div><?php endif; ?><?php if (is_user_logged_in() && $plazas > 0) : ?><button class="w-full px-6 py-3 bg-primary text-white rounded-lg hover:bg-primary-dark font-bold mb-3">Inscribirse</button><?php elseif (!is_user_logged_in()) : ?><a href="<?php echo wp_login_url(get_permalink()); ?>" class="block text-center w-full px-6 py-3 bg-primary text-white rounded-lg font-bold">Inicia sesión</a><?php else : ?><button disabled class="w-full px-6 py-3 bg-gray-300 rounded-lg font-bold">Plazas agotadas</button><?php endif; ?></div></aside></div></div><?php endwhile; get_footer(); ?>
